.darma-loader-darma-custom-112 {
  --c:no-repeat linear-gradient(var(--loader-color, #ffa500) 0 0);
  background: 
    var(--c),var(--c),var(--c),
    var(--c),var(--c),var(--c),
    var(--c),var(--c),var(--c);
  background-size: 16px 16px;
  animation: 
    darma-loader-darma-custom-112-l32-1 1s infinite,
    darma-loader-darma-custom-112-l32-2 1s infinite;
}
@keyframes darma-loader-darma-custom-112-l32-1 {
  0%,100% {width:45px;height: 45px}
  35%,65% {width:65px;height: 65px}
}
@keyframes darma-loader-darma-custom-112-l32-2 {
  0%,40%  {background-position: 0 0,0 50%, 0 100%,50% 100%,100% 100%,100% 50%,100% 0,50% 0,  50% 50% }
  60%,100%{background-position: 0 50%, 0 100%,50% 100%,100% 100%,100% 50%,100% 0,50% 0,0 0,  50% 50% }
}

